@@ -6529,9 +6529,21 @@ struct StatementLookasideGrowthGuard<'a> {

 impl<'a> StatementLookasideGrowthGuard<'a> {
     fn new(conn: &'a Connection) -> Self {
+        // PERF-B1: capturing retained-bytes requires five RefCell::borrow()s
+        // across scratch buffers. In release builds `hot_path_profile_enabled`
+        // is always false, so the growth delta is never consumed — skip the
+        // capture on the cold path. When profiling is enabled at runtime we
+        // record from the current snapshot; the only observable difference is
+        // that a single instrumentation sample across a profile toggle reads
+        // growth=0, which is acceptable for a diagnostic counter.
+        let before_bytes = if hot_path_profile_enabled() {
+            conn.statement_lookaside_retained_bytes()
+        } else {
+            0
+        };
         Self {
             conn,
-            before_bytes: conn.statement_lookaside_retained_bytes(),
+            before_bytes,
         }
     }
 }
